parameters.jsCode:
let text = $json.output;
if (typeof text === 'string') {
  text = text.replace(/\u0060\u0060\u0060json|\u0060\u0060\u0060/g, '').trim();
  try {
    return { json: { output: JSON.parse(text) } };
  } catch (e) {
    return { json: { output: {} } };
  }
}
return { json: { output: text } };

parameters.text:
=Topic: {{ $json.output.topic }}
Target Audience: {{ $json.output.target_audience }}
Content Bucket: {{ $json.output.content_bucket }}
Category: {{ $json.output.category }}

Ideas: {{ $json.output.ideas }}

Select only the top 3 ideas with highest engagement potential.
Return only JSON:
{
  "category": "{{ $json.output.category }}",
  "top_3_ideas": ["idea1", "idea2", "idea3"],
  "topic": "{{ $json.output.topic }}",
  "content_bucket": "{{ $json.output.content_bucket }}",
  "target_audience": "{{ $json.output.target_audience }}"
}

parameters.jsCode:
const rows = ($json.output.ideas || []).map(idea => ({
  json: {
    Category: $json.output.category || "",
    Content_Bucket: $json.output.content_bucket || "",
    Target_Audience: $json.output.target_audience || "",
    Idea: idea || ""
  }
}));
return rows;

const items = $input.all();
const out = [];
for (const item of items) {
  const r = item.json;
  if (String(r.Approval).toLowerCase() === "yes") {
    const targetAudienceArray = r.Target_Audience ? r.Target_Audience.split(",").map(a => a.trim()) : [];
    const tags = [
      ...(r.Category ? [r.Category] : []),
      ...(r.Content_Bucket ? [r.Content_Bucket] : []),
      ...targetAudienceArray
    ];
    out.push({
      json: {
        idea: r.Idea,
        category: r.Category || null,
        content_bucket: r.Content_Bucket || null,
        target_audience: targetAudienceArray,
        tags: tags
      }
    });
  }
}
return out;

