parameters.jsCode:
const config = $json; 
const out = [];
for (const contentType in config) {
  for (const subtype in config[contentType]) {
    for (const platform in config[contentType][subtype]) {
      const data = config[contentType][subtype][platform];
      out.push({
        contentType,
        subtype,
        platform,
        type: data.type,
        media_type: data.media_type,
        size: data.size
      });
    }
  }
}
return out.map(x => ({ json: x }));

const ideas = $items("Filter: Approved Ideas").map(i => i.json);
const configs = items.map(i => i.json);
const out = [];
for (const idea of ideas) {
  for (const cfg of configs) {
    out.push({
      json: { ...idea, ...cfg }
    });
  }
}
return out;

